     1→/**
     2→ * A single text chunk from Postgres — shared input type for all enrichments.
     3→ */
     4→export interface TextChunk {
     5→    id: string;
     6→    text: string | null;
     7→}
     8→
     9→/**
    10→ * Contextual information passed to every enrichment during a pipeline run.
    11→ * Carries document-level metadata that individual enrichments may need.
    12→ */
    13→export interface EnrichmentContext {
    14→    documentSourceId: string;
    15→    neo4jCredentials?: Record<string, unknown>;
    16→    transactionId?: string;
    17→}
    18→
    19→/**
    20→ * The minimum shape that every enrichment result must satisfy.
    21→ * Individual enrichments may extend this with their own typed metadata.
    22→ */
    23→export interface EnrichmentResult {
    24→    /** Must match the enrichment's {@link ITextEnrichment.name}. */
    25→    enrichmentName: string;
    26→    /** Total number of entities/items extracted across all chunks. */
    27→    extracted: number;
    28→    /** Optional per-enrichment breakdown or debug info. */
    29→    metadata?: Record<string, unknown>;
    30→}
    31→
    32→/**
    33→ * The contract every text enrichment definition must implement.
    34→ *
    35→ * Each implementation is responsible for:
    36→ *  1. Running its own extraction logic over the supplied chunks.
    37→ *  2. Persisting results to Neo4j (or any other sink) via its injected repositories.
    38→ *  3. Returning a typed {@link EnrichmentResult} for the pipeline to aggregate.
    39→ *
    40→ * Implementations are plain injectable NestJS services — they carry their own
    41→ * repository dependencies and are registered with the {@link TextEnrichmentManager}
    42→ * at module initialisation time.
    43→ *
    44→ * @example
    45→ * ```typescript
    46→ * @Injectable()
    47→ * export class RequirementEnrichment implements ITextEnrichment {
    48→ *     readonly name = 'requirements';
    49→ *     readonly description = 'Extracts normative requirement sentences (must/shall/will)';
    50→ *     constructor(private readonly repo: RequirementsRepository) {}
    51→ *     async processChunks(chunks, context) { ... }
    52→ * }
    53→ * ```
    54→ */
    55→export interface ITextEnrichment<TResult extends EnrichmentResult = EnrichmentResult> {
    56→    /** Unique stable identifier used as the key in pipeline results. */
    57→    readonly name: string;
    58→    /** Human-readable description of what this enrichment extracts. */
    59→    readonly description: string;
    60→    /**
    61→     * Run the enrichment over the supplied chunks and persist any results.
    62→     *
    63→     * @param chunks  - Text chunks fetched from Postgres by the pipeline.
    64→     * @param context - Document-level metadata shared across the pipeline run.
    65→     * @returns A result object describing what was extracted.
    66→     */
    67→    processChunks(chunks: TextChunk[], context: EnrichmentContext): Promise<TResult>;
    68→}
